            // Deve usar operador BETWEEN
            resultado.Value.where.Should().Contain($"[{DBNECompromissosDicInfo.PTabelaNome}].{DBNECompromissosDicInfo.QuemCad} BETWEEN @{DBNECompromissosDicInfo.QuemCad} AND @{DBNECompromissosDicInfo.QuemCad}_end");
